$modal = '<div id="modal-checkout" style="display:none; position:fixed; inset:0; z-index:9999; background:rgba(0,0,0,.7); align-items:center; justify-content:center; padding:16px;"><div style="background:#fff; border-radius:20px; max-width:480px; width:100%; overflow:hidden; box-shadow:0 25px 60px rgba(0,0,0,.4);"><div style="background:linear-gradient(135deg,#1a1a2e,#0f3460); padding:24px; color:#fff; display:flex; justify-content:space-between; align-items:center;"><div><div style="font-size:12px; opacity:.7; letter-spacing:1px; text-transform:uppercase;">ALPE Ar Condicionado</div><div id="checkout-nome" style="font-size:20px; font-weight:700; margin-top:4px;">Produto</div></div><button onclick="fecharCheckout()" style="background:rgba(255,255,255,.15); border:0; color:#fff; width:36px; height:36px; border-radius:50%; font-size:20px; cursor:pointer;">&times;</button></div><div style="padding:20px 24px; border-bottom:1px solid #eee; display:flex; align-items:center; justify-content:space-between;"><div><div style="font-size:13px; color:#666;">Valor total</div><div id="checkout-preco" style="font-size:32px; font-weight:800; color:#0f3460;">R$ 0,00</div></div><div style="text-align:right;"><div style="font-size:12px; color:#25d366; font-weight:700;">5% OFF no PIX</div><div id="checkout-preco-pix" style="font-size:18px; font-weight:700; color:#25d366;">R$ 0,00</div></div></div><div style="padding:20px 24px;"><div style="font-size:13px; font-weight:700; color:#333; margin-bottom:14px; text-transform:uppercase; letter-spacing:.5px;">Como deseja pagar?</div><button onclick="pagarBTG(''pix'')" style="width:100%; padding:16px; margin-bottom:10px; border:2px solid #25d366; border-radius:12px; background:#f0fff4; cursor:pointer; display:flex; align-items:center; gap:14px;"><div style="text-align:left; flex:1;"><div style="font-weight:700; color:#166534;">PIX - Pagamento Instantaneo</div><div style="font-size:12px; color:#16a34a;">5% de desconto - Aprovado na hora</div></div><div style="font-weight:800; color:#166534;" id="btn-preco-pix">R$ 0,00</div></button><button onclick="pagarBTG(''cartao'')" style="width:100%; padding:16px; margin-bottom:10px; border:2px solid #0f3460; border-radius:12px; background:#f0f4ff; cursor:pointer; display:flex; align-items:center; gap:14px;"><div style="text-align:left; flex:1;"><div style="font-weight:700; color:#0f3460;">Cartao de Credito</div><div style="font-size:12px; color:#3b5998;">Ate 8x sem juros - Visa, Master, Elo</div></div><div style="font-weight:800; color:#0f3460;" id="btn-preco-cartao">R$ 0,00</div></button><button onclick="pagarBTG(''boleto'')" style="width:100%; padding:16px; margin-bottom:10px; border:2px solid #f59e0b; border-radius:12px; background:#fffbeb; cursor:pointer; display:flex; align-items:center; gap:14px;"><div style="text-align:left; flex:1;"><div style="font-weight:700; color:#92400e;">Boleto Bancario</div><div style="font-size:12px; color:#b45309;">Vencimento em 3 dias uteis</div></div><div style="font-weight:800; color:#92400e;" id="btn-preco-boleto">R$ 0,00</div></button><button onclick="negociarWhatsApp()" style="width:100%; padding:16px; border:2px solid #25d366; border-radius:12px; background:#fff; cursor:pointer; display:flex; align-items:center; gap:14px;"><div style="text-align:left; flex:1;"><div style="font-weight:700; color:#166534;">Negociar pelo WhatsApp</div><div style="font-size:12px; color:#16a34a;">Fale com um especialista agora</div></div></button></div><div style="padding:12px 24px 20px; text-align:center; color:#999; font-size:11px;">Pagamento seguro via BTG Pay - Dados criptografados</div></div></div><script>var _p={};function abrirCheckout(id,nome,preco){_p={id:id,nome:nome,preco:preco};var cfg=window.BTG_CONFIG;var px=preco*(1-cfg.descPix/100);var f=function(v){return v.toLocaleString("pt-BR",{style:"currency",currency:"BRL"});};document.getElementById("checkout-nome").textContent=nome;document.getElementById("checkout-preco").textContent=f(preco);document.getElementById("checkout-preco-pix").textContent=f(px)+" no PIX";document.getElementById("btn-preco-pix").textContent=f(px);document.getElementById("btn-preco-cartao").textContent=f(preco);document.getElementById("btn-preco-boleto").textContent=f(preco);document.getElementById("modal-checkout").style.display="flex";document.body.style.overflow="hidden";}function fecharCheckout(){document.getElementById("modal-checkout").style.display="none";document.body.style.overflow="";}function pagarBTG(m){var cfg=window.BTG_CONFIG;var f=function(v){return v.toLocaleString("pt-BR",{style:"currency",currency:"BRL"});};var mt=m==="pix"?"PIX":m==="cartao"?"Cartao de Credito":"Boleto";var msg=encodeURIComponent("Ola ALPE! Quero comprar: "+_p.nome+" por "+f(_p.preco)+". Pagamento: "+mt);window.open("https://api.whatsapp.com/send?phone="+cfg.whatsapp+"&text="+msg,"_blank");fecharCheckout();}function negociarWhatsApp(){var cfg=window.BTG_CONFIG;var f=function(v){return v.toLocaleString("pt-BR",{style:"currency",currency:"BRL"});};var msg=encodeURIComponent("Ola ALPE! Tenho interesse em: "+_p.nome+" ("+f(_p.preco)+"). Podemos negociar?");window.open("https://api.whatsapp.com/send?phone="+cfg.whatsapp+"&text="+msg,"_blank");fecharCheckout();}document.getElementById("modal-checkout").addEventListener("click",function(e){if(e.target===this)fecharCheckout();});</script>'

$c = Get-Content 'index.html' -Raw -Encoding UTF8
$c = $c -replace '</body>', ($modal + "`n</body>")
Set-Content 'index.html' -Value $c -NoNewline -Encoding UTF8
Write-Host "OK - modal inserido"
